// Determinar el momento del día y calcular fechas de análisis
const now = new Date();

// Ajustar a timezone de Colombia (UTC-5)
const colombiaOffset = -5 * 60;
const utc = now.getTime() + (now.getTimezoneOffset() * 60000);
const colombiaTime = new Date(utc + (colombiaOffset * 60000));

// Determinar momento del día basado en la hora actual
let timeOfDay = 'morning';
const currentHour = colombiaTime.getHours();

if (currentHour >= 11 && currentHour < 16) {
  timeOfDay = 'morning'; // Revisar hábitos de la mañana
} else if (currentHour >= 15 && currentHour < 22) {
  timeOfDay = 'afternoon'; // Revisar hábitos de la tarde
} else {
  timeOfDay = 'night'; // Revisar hábitos de la noche
}

// Generar fechas de los últimos 7 días
const dates = [];
for (let i = 0; i < 7; i++) {
  const date = new Date(colombiaTime);
  date.setDate(date.getDate() - i);
  dates.push({
    dateString: date.toISOString().split('T')[0], // YYYY-MM-DD format
    dateFormatted: date.toLocaleDateString('es-CO'),
    isToday: i === 0,
    year: date.getFullYear(),
    month: date.getMonth() + 1 // 1-based month
  });
}

// Generar document ID dinámicamente para el mes actual
const currentYear = colombiaTime.getFullYear();
const currentMonth = String(colombiaTime.getMonth() + 1).padStart(2, '0');
const currentMonthDocumentId = `HPiS7rrqvKVm9uZBV8sHzW8wQz33_${currentYear}-${currentMonth}`;

// Hábitos por momento del día
const habitsByTime = {
