    { id: 7, name: 'Tender la cama', icon: '🛏️' },
    { id: 20, name: 'Lavar loza del desayuno', icon: '🧽' }
  ],
  afternoon: [
    { id: 8, name: 'Almuerzo', icon: '🍽️' },
    { id: 9, name: 'Siesta', icon: '🛌' },
    { id: 10, name: 'Lavarme los dientes', icon: '🪥' },
    { id: 11, name: 'Seda Dental', icon: '🦷' },
    { id: 19, name: 'Tomar agua (tarde)', icon: '💧' }
  ],
  night: [
    { id: 12, name: 'Cena', icon: '🍽️' },
    { id: 13, name: 'Lavarme los dientes', icon: '🪥' },
    { id: 14, name: 'Seda Dental', icon: '🦷' },
    { id: 15, name: 'Llevar el diario', icon: '📓' },
    { id: 16, name: 'Botar algo que no sirva', icon: '🗑️' },
    { id: 17, name: 'Organizar la cocina', icon: '🍴' },
    { id: 18, name: 'Lectura', icon: '📚' },
    { id: 21, name: 'Lista de pendientes', icon: '📝' }
  ]
};

return {
  timeOfDay: timeOfDay,
  currentHour: currentHour,
  dates: dates,
  currentMonthDocumentId: currentMonthDocumentId,
  habitsToCheck: habitsByTime[timeOfDay],
  analysisContext: {
    morningCheck: timeOfDay === 'morning' ? 'Revisando hábitos matutinos' : null,
    afternoonCheck: timeOfDay === 'afternoon' ? 'Revisando hábitos de la tarde' : null,
    nightCheck: timeOfDay === 'night' ? 'Revisando hábitos nocturnos' : null
  }
};

// Procesar datos de hábitos del documento mensual
const inputData = $input.first().json;

// RECALCULAR CONTEXTO
const now = new Date();
const colombiaOffset = -5 * 60;
const utc = now.getTime() + (now.getTimezoneOffset() * 60000);
const colombiaTime = new Date(utc + (colombiaOffset * 60000));

// Determinar momento del día
let timeOfDay = 'morning';
const currentHour = colombiaTime.getHours();

if (currentHour >= 1 && currentHour < 12) {
  timeOfDay = 'morning';
} else if (currentHour >= 12 && currentHour < 18) {
  timeOfDay = 'afternoon';
} else {
  timeOfDay = 'night';
}

// Generar fechas de los últimos 7 días
const dates = [];
for (let i = 0; i < 7; i++) {
  const date = new Date(colombiaTime);
  date.setDate(date.getDate() - i);

  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, '0');
  const day = String(date.getDate()).padStart(2, '0');
  const dateString = `${year}-${month}-${day}`;

  dates.push({
    dateString: dateString,
    dateFormatted: date.toLocaleDateString('es-CO'),
    isToday: i === 0
  });
}

// Hábitos por momento del día
const habitsByTime = {
  morning: [
    { id: 1, name: 'Tomar Agua (mañana)', icon: '💧', category: 'health' },
    { id: 2, name: 'Ejercicio', icon: '🎾', category: 'fitness' },
    { id: 3, name: 'Ducha fria', icon: '🚿', category: 'wellness' },
    { id: 4, name: 'Desayuno', icon: '🍳', category: 'nutrition' },
    { id: 5, name: 'Lavarme los dientes', icon: '🪥', category: 'hygiene' },
    { id: 6, name: 'Seda Dental', icon: '🦷', category: 'hygiene' },
    { id: 7, name: 'Tender la cama', icon: '🛏️', category: 'organization' },
    { id: 20, name: 'Lavar loza del desayuno', icon: '🧽', category: 'organization' }
  ],
  afternoon: [
    { id: 8, name: 'Almuerzo', icon: '🍽️', category: 'nutrition' },
    { id: 9, name: 'Siesta', icon: '🛌', category: 'wellness' },
    { id: 10, name: 'Lavarme los dientes', icon: '🪥', category: 'hygiene' },
    { id: 11, name: 'Seda Dental', icon: '🦷', category: 'hygiene' },
    { id: 19, name: 'Tomar agua (tarde)', icon: '💧', category: 'health' }
  ],
  night: [
    { id: 12, name: 'Cena', icon: '🍽️', category: 'nutrition' },
    { id: 13, name: 'Lavarme los dientes', icon: '🪥', category: 'hygiene' },
    { id: 14, name: 'Seda Dental', icon: '🦷', category: 'hygiene' },
    { id: 15, name: 'Llevar el diario', icon: '📓', category: 'personal_development' },
    { id: 16, name: 'Botar algo que no sirva', icon: '🗑️', category: 'organization' },
    { id: 17, name: 'Organizar la cocina', icon: '🍴', category: 'organization' },
    { id: 18, name: 'Lectura', icon: '📚', category: 'personal_development' },
    { id: 21, name: 'Lista de pendientes', icon: '📝', category: 'productivity' }
  ]
};

const habitsToCheck = habitsByTime[timeOfDay];

// EXTRAER DATOS DE FIRESTORE
let monthlyHabitsDoc = {};
if (Array.isArray(inputData) && inputData.length > 0) {
  const firestoreDoc = inputData[0];
  if (firestoreDoc.habits) {
    monthlyHabitsDoc = firestoreDoc;
  }
} else if (inputData.habits) {
  monthlyHabitsDoc = inputData;
} else {
  monthlyHabitsDoc = { habits: {} };
}

const habitsMap = monthlyHabitsDoc?.habits || {};

// ANÁLISIS POR HÁBITOS
const habitAnalysis = {};
let totalCompletedToday = 0;
let totalPossibleToday = habitsToCheck.length;

habitsToCheck.forEach(habit => {
  const analysis = {
    id: habit.id,
    name: habit.name,
    icon: habit.icon,
    category: habit.category,
    weekData: [],
    completedDays: 0,
    missedDays: 0,
    currentStreak: 0,
    isCompletedToday: false,
    weekCompletionRate: 0,
    severity: 'good',
    severityScore: 0 // Para ordenamiento más preciso
  };

  // Analizar cada día para este hábito
  dates.forEach(dateInfo => {
    const habitKey = `${habit.id}_${dateInfo.dateString}`;
    const isCompleted = habitsMap[habitKey] === true;

    analysis.weekData.push({
      date: dateInfo.dateFormatted,
      isToday: dateInfo.isToday,
      completed: isCompleted
    });

    if (isCompleted) {
      analysis.completedDays++;
      if (dateInfo.isToday) {
        analysis.isCompletedToday = true;
        totalCompletedToday++;
      }
    } else {
      analysis.missedDays++;
    }
  });

  // Calcular rachas (positiva y negativa)
  let positiveStreak = 0; // días consecutivos completando
  let negativeStreak = 0; // días consecutivos sin completar

  for (let i = 0; i < dates.length; i++) {
    const dateInfo = dates[i];
    const habitKey = `${habit.id}_${dateInfo.dateString}`;
    const isCompleted = habitsMap[habitKey] === true;

    if (isCompleted) {
      positiveStreak++;
      if (negativeStreak === 0) continue; // Si ya estábamos en racha positiva, seguir
      else break; // Si veníamos de racha negativa, parar
    } else {
      negativeStreak++;
      if (positiveStreak === 0) continue; // Si ya estábamos en racha negativa, seguir  
      else break; // Si veníamos de racha positiva, parar
    }
  }

  analysis.positiveStreak = positiveStreak;
  analysis.negativeStreak = negativeStreak;
  analysis.currentStreak = positiveStreak > 0 ? positiveStreak : -negativeStreak; // Positivo si bueno, negativo si malo

  // Determinar severidad con score para mejor ordenamiento
  const absStreak = Math.abs(analysis.currentStreak);

  if (analysis.currentStreak < 0) { // Racha negativa (malo)
    if (absStreak >= 3) {
      analysis.severity = 'critical';
      analysis.severityScore = 4;
    } else if (absStreak >= 2) {
      analysis.severity = 'warning';
      analysis.severityScore = 3;
    } else if (absStreak >= 1) {
      analysis.severity = 'mild';
      analysis.severityScore = 2;
    }
  } else { // Racha positiva o neutral (bueno)
    analysis.severity = 'good';
    analysis.severityScore = 1;
  }

  analysis.weekCompletionRate = (analysis.completedDays / 7) * 100;
  habitAnalysis[habit.id] = analysis;
});

// ESTADÍSTICAS POR CATEGORÍA
const categoryStats = {};
const categories = [...new Set(habitsToCheck.map(h => h.category))];

categories.forEach(category => {
  const categoryHabits = Object.values(habitAnalysis).filter(h => h.category === category);
  categoryStats[category] = {
    totalHabits: categoryHabits.length,
    completedToday: categoryHabits.filter(h => h.isCompletedToday).length,
    averageCompletionRate: categoryHabits.reduce((sum, h) => sum + h.weekCompletionRate, 0) / categoryHabits.length,
    problemHabits: categoryHabits.filter(h => h.severity !== 'good').length
  };
});

// HÁBITOS PROBLEMÁTICOS (mejorado)
const problemHabits = Object.values(habitAnalysis)
  .filter(analysis => analysis.severity !== 'good')
  .sort((a, b) => {
    // Ordenar por severityScore y luego por peor racha negativa
    if (a.severityScore !== b.severityScore) {
      return b.severityScore - a.severityScore;
    }
    return a.currentStreak - b.currentStreak; // Más negativo = peor
  });

// ESTADÍSTICAS GENERALES
const weekStats = {
  period: `${dates[6].dateFormatted} - ${dates[0].dateFormatted}`,
  timeOfDay: timeOfDay,
  currentTime: colombiaTime.toISOString(),
  todayCompletionRate: totalPossibleToday > 0 ? (totalCompletedToday / totalPossibleToday) * 100 : 0,
  totalHabitsToCheck: totalPossibleToday,
  completedToday: totalCompletedToday,
  missedToday: totalPossibleToday - totalCompletedToday,
  averageWeekCompletionRate: Object.values(habitAnalysis).reduce((sum, h) => sum + h.weekCompletionRate, 0) / habitsToCheck.length,
  habitsCountBySeverity: {
    good: Object.values(habitAnalysis).filter(h => h.severity === 'good').length,
    mild: Object.values(habitAnalysis).filter(h => h.severity === 'mild').length,
    warning: Object.values(habitAnalysis).filter(h => h.severity === 'warning').length,
    critical: Object.values(habitAnalysis).filter(h => h.severity === 'critical').length
  },
  categoryStats: categoryStats
};

// DETERMINAR SI NECESITA INTERVENCIÓN
const needsIntervention = weekStats.habitsCountBySeverity.critical > 0 || 
                         weekStats.todayCompletionRate < 99 ||
                         problemHabits.length >= 1;

// GENERAR RECOMENDACIONES ESPECÍFICAS
const recommendations = [];

if (problemHabits.length > 0) {
  const criticalHabits = problemHabits.filter(h => h.severity === 'critical');
  const warningHabits = problemHabits.filter(h => h.severity === 'warning');

  if (criticalHabits.length > 0) {
    recommendations.push({
      type: 'urgent',
      message: `Atención inmediata requerida para ${criticalHabits.length} hábito(s) crítico(s)`,
      habits: criticalHabits.map(h => ({ 
        id: h.id, 
        name: h.name, 
        negativeStreak: Math.abs(h.currentStreak),
        daysWithoutDoing: h.negativeStreak
      }))
    });
  }

  if (warningHabits.length > 0) {
    recommendations.push({
      type: 'moderate',
      message: `${warningHabits.length} hábito(s) en riesgo de volverse crítico(s)`,
      habits: warningHabits.map(h => ({ 
        id: h.id, 
        name: h.name, 
        negativeStreak: Math.abs(h.currentStreak),
        daysWithoutDoing: h.negativeStreak
      }))
    });
  }
}

// Recomendaciones por categoría problemática
Object.entries(categoryStats).forEach(([category, stats]) => {
  if (stats.problemHabits > 0) {
    recommendations.push({
      type: 'category',
      message: `Categoría "${category}" necesita atención: ${stats.problemHabits}/${stats.totalHabits} hábitos problemáticos`,
      category: category,
      completionRate: stats.averageCompletionRate
    });
  }
});

return [{
  json: {
    // CONTEXTO Y METADATOS
    context: {
      analysisTime: colombiaTime.toISOString(),
      timeOfDay: timeOfDay,
      currentHour: currentHour,
      period: weekStats.period
    },

    // RESUMEN EJECUTIVO PRIMERO (lo más importante para la IA)
    summary: {
      needsIntervention: needsIntervention,
      overallStatus: needsIntervention ? 'needs_attention' : 'good',
      todayCompletionRate: weekStats.todayCompletionRate,
      weeklyCompletionRate: weekStats.averageWeekCompletionRate,
      totalProblems: problemHabits.length,
      criticalCount: weekStats.habitsCountBySeverity.critical,
      warningCount: weekStats.habitsCountBySeverity.warning,
      // Múltiples perspectivas del hábito más problemático
      primaryConcerns: {
        bySeverityAndStreak: problemHabits.length > 0 ? problemHabits[0] : null,
        byWorstNegativeStreak: problemHabits.length > 0 ? problemHabits.reduce((worst, habit) => 
          habit.currentStreak < worst.currentStreak ? habit : worst, problemHabits[0]) : null,
        byLowestCompletion: problemHabits.length > 0 ? problemHabits.reduce((min, habit) => 
          habit.weekCompletionRate < min.weekCompletionRate ? habit : min, problemHabits[0]) : null
      },
      topPriorityHabits: problemHabits.slice(0, 3),
      worstStreaks: problemHabits.slice().sort((a, b) => a.currentStreak - b.currentStreak).slice(0, 3) // Los 3 con peor racha negativa
    },

    // RECOMENDACIONES ESPECÍFICAS
    recommendations: recommendations,

    // ESTADÍSTICAS DETALLADAS
    statistics: {
      weekly: weekStats,
      byCategory: categoryStats,
      daily: {
        completed: totalCompletedToday,
        total: totalPossibleToday,
        remaining: totalPossibleToday - totalCompletedToday
      }
    },

    // HÁBITOS QUE NECESITAN ATENCIÓN
    habits: {
      problems: problemHabits,
      pendingToday: Object.values(habitAnalysis).filter(h => !h.isCompletedToday)
        .map(h => ({
          id: h.id,
          name: h.name,
          icon: h.icon,
          category: h.category,
          severity: h.severity,
          negativeStreak: h.negativeStreak,
          weekCompletionRate: h.weekCompletionRate
        }))
    }
  }
}];
